UPDATE headstones
SET
  longitude = reviewed_updates.longitude,
  latitude = reviewed_updates.latitude,
  geometry = ST_SetSRID(
    ST_MakePoint(reviewed_updates.longitude::double precision, reviewed_updates.latitude::double precision),
    4326
  )::geometry(Point, 4326),
  source_properties = jsonb_set(
    headstones.source_properties,
    '{ShapefileGeometryUpdate}',
    jsonb_build_object(
      'source', 'TrinityCemeteryFinal3.shp',
      'coordinateSource', 'shapefile geometry',
      'reviewedBy', 'manual review and mutual-nearest reconciliation',
      'reviewedAt', '2026-06-18',
      'matchConfidence', reviewed_updates.match_confidence,
      'matchReasons', reviewed_updates.match_reasons,
      'distanceFeet', reviewed_updates.distance_feet,
      'shapefileFeatureIndex', reviewed_updates.shapefile_feature_index,
      'shapefileTitle', reviewed_updates.shapefile_title,
      'shapefileName', reviewed_updates.shapefile_name,
      'previousLongitude', ST_X(headstones.geometry),
      'previousLatitude', ST_Y(headstones.geometry)
    ),
    true
  ),
  updated_at = now()
FROM reviewed_updates
WHERE headstones.deleted_at IS NULL
  AND headstones.headstone_id = reviewed_updates.headstone_id;

--rollback WITH previous_points AS (SELECT headstones.id, (headstones.source_properties #>> '{ShapefileGeometryUpdate,previousLongitude}')::double precision AS longitude, (headstones.source_properties #>> '{ShapefileGeometryUpdate,previousLatitude}')::double precision AS latitude FROM headstones WHERE headstones.source_properties #> '{ShapefileGeometryUpdate}' IS NOT NULL) UPDATE headstones SET longitude = previous_points.longitude, latitude = previous_points.latitude, geometry = ST_SetSRID(ST_MakePoint(previous_points.longitude, previous_points.latitude), 4326)::geometry(Point, 4326), source_properties = headstones.source_properties - 'ShapefileGeometryUpdate', updated_at = now() FROM previous_points WHERE headstones.id = previous_points.id;
